INSERT INTO `heroes` VALUES (1,'Abdul Muis','Agam, Sumatera Barat','1886-07-03','1959-06-17','Seorang sastrawan, politikus, dan wartawan Indonesia. Dia merupakan pengurus besar Sarekat Islam dan pernah menjadi anggota Volksraad mewakili organisasi tersebut',NULL,NULL),(2,'Ki Hajar Dewantara','Yogyakarta','1889-05-02','1959-04-26','Pengajar dan menteri pemerintahan, mendirikan Taman Siswa, saudara Suryopranoto',NULL,NULL),(3,'R.M. Surjopranoto','Yogyakarta','1871-01-11','1959-10-15','Pengajar dan tokoh hak-hak buruh, saudara Ki Hajar Dewantara',NULL,NULL),(4,'Mohammad Hoesni Thamrin','Jakarta','1894-02-16','1941-01-11','Seorang politisi era Hindia Belanda berasal dari Betawi yang kemudian dianugerahi gelar pahlawan nasional Indonesia. Ayahnya adalah seorang Belanda dengan ibu orang Betawi. Sejak kecil ia dirawat oleh pamannya dari pihak ibu karena ayahnya meninggal, sehingga ia tidak menyandang nama Belanda.',NULL,NULL),(5,'KH. Samanhudi','Surakarta, Jawa Tengah','1868-10-08','1956-12-28','Seorang pengusaha dan juga mendirikan Sarekat Islam',NULL,NULL),(6,'H.O.S. Cokroaminoto','Madiun, Jawa Timur','1882-08-16','1934-12-17','Politisi, Pemimpin Sarekat Islam dan menjadi salah satu mentor dari Presiden Soekarno',NULL,NULL),(7,'Dr. Ernest François Eugène Douwes Dekker (Danudirja Setiabudi)','Pasuruan, Jawa Timur','1879-10-08','1950-08-28','Jurnalis dan politisi Indonesia yang membantu kemerdekaan Indonesia',NULL,NULL),(8,'Sisingamangaradja XII','Tapanuli, Sumatera Utara','1849-02-18','1907-06-17','Pemimpin Batak yang melakukan kampanye gerilyawan melawan pasukan kolonial Belanda',NULL,NULL),(9,'Dr. G.S.S.J Ratulangie','Tondano, Sulawesi Utara','1890-11-05','1949-06-30','Politisi Minahasa dan pendukung kemerdekaan Indonesia',NULL,NULL),(10,'Dr. Sutomo','Nganjuk, Jawa Timur','1888-07-30','1938-05-30','Tokoh pendiri Budi Utomo, organisasi pergerakan yang pertama di Indonesia',NULL,NULL),(11,'KH. Ahmad Dahlan','Yogyakarta','1868-08-01','1923-02-23','Pemimpin Islam Jawa, mend